module comparator_2bit (
    input [1:0] cmp_A,
    input [1:0] B,
    output reg A_gt_B,
    output reg A_eq_B,
    output reg A_lt_B
);

always @(*) begin
    if (cmp_A > B) begin
        A_gt_B = 1'b1;
        A_eq_B = 1'b0;
        A_lt_B = 1'b0;
    end else if (cmp_A == B) begin
        A_gt_B = 1'b0;
        A_eq_B = 1'b1;
        A_lt_B = 1'b0;
    end else begin
        A_gt_B = 1'b0;
        A_eq_B = 1'b0;
        A_lt_B = 1'b1;
    end
end

endmodule
